18	namespace slang_frontend {
19	
20	struct VariableBit
21	{
22		Variable variable;
23		uint64_t offset;
24	
25		typedef std::tuple<Variable, uint64_t> Label;
26		Label label() const { return std::make_tuple(variable, offset); }
27	
28		bool operator==(const VariableBit &other) const { return label() == other.label(); }
29		bool operator<(const VariableBit &other) const { return label() < other.label(); }
30	#if YS_HASHING_VERSION >= 1
31		[[nodiscard]] Yosys::Hasher hash_into(Yosys::Hasher h) const
32		{
33			h.eat(label());
34			return h;
35		}
36	#else
37		int hash() const { return Yosys::hash_ops<Label>::hash(label()); }
38	#endif
39	
40		std::string index_text() const
41		{
42			if (variable.bitwidth() == 1)
43				return "";
44			else
45				return Yosys::stringf("[%" PRIu64 "]", offset);
46		}
47	
48		std::string text() const { return variable.text() + index_text(); }
49	};
50	
51	// VariableChunk is to VariableBit
52	// what RTLIL::SigChunk is to RTLIL::SigBit
53	struct VariableChunk
54	{
55		Variable variable;
56		uint64_t base;
57		uint64_t length;
58	
59		uint64_t bitwidth() const { return length; }
60	
61		VariableBit operator[](uint64_t key) const
62		{
63			log_assert(key < length);
64			return VariableBit{variable, base + key};
65		}
66	
67		bool operator==(const VariableChunk &other) const
68		{
69			return variable == other.variable && base == other.base && length == other.length;
70		}
71	
72		std::string slice_text() const
73		{
74			if (length == variable.bitwidth())
75				return "";
76			else if (length > 1)
77				// TODO: hdl indices
78				return Yosys::stringf("[%" PRIu64 ":%" PRIu64 "]", base + length - 1, base);
79			else
80				return Yosys::stringf("[%" PRIu64 "]", base);
81		}
82	
83		std::string text() const { return variable.text() + slice_text(); }
84	};
85	
86	class VariableBits
87	{
88		std::variant<VariableChunk, std::vector<VariableBit>> storage_;
89	
90		bool is_chunk() const { return std::holds_alternative<VariableChunk>(storage_); }
91	
92		VariableChunk &as_chunk() { return std::get<VariableChunk>(storage_); }
93		const VariableChunk &as_chunk() const { return std::get<VariableChunk>(storage_); }
94	
95		std::vector<VariableBit> &as_bits() { return std::get<std::vector<VariableBit>>(storage_); }
96		const std::vector<VariableBit> &as_bits() const
97		{
98			return std::get<std::vector<VariableBit>>(storage_);
99		}
100	
101		void unpack()
102		{
103			if (!is_chunk())
104				return;
105			VariableChunk chunk = as_chunk();
106			std::vector<VariableBit> bits;
107			bits.reserve(chunk.length);
108			for (uint64_t i = 0; i < chunk.length; i++)
109				bits.push_back(chunk[i]);
110			storage_ = std::move(bits);
111		}
112	
113	public:
114		VariableBits() : storage_(VariableChunk{{}, 0, 0}) {}
115	
116		VariableBits(const VariableBit &bit) : storage_(VariableChunk{bit.variable, bit.offset, 1}) {}
117	
118		VariableBits(const VariableChunk &chunk) : storage_(chunk) {}
119	
120		VariableBits(const Variable &variable)
121			: storage_(VariableChunk{variable, 0, variable.bitwidth()})
122		{}
123	
124		VariableBits(std::initializer_list<VariableBits> parts) : storage_(VariableChunk{{}, 0, 0})
125		{
126			for (auto it = std::rbegin(parts); it != std::rend(parts); it++) {
127				append(*it);
128			}
129		}
130	
131		uint64_t bitwidth() const
132		{
133			if (is_chunk())
134				return as_chunk().length;
135			else
136				return as_bits().size();
137		}
138	
139		bool empty() const { return bitwidth() == 0; }
140	
141		VariableBit operator[](uint64_t index) const
142		{
143			if (is_chunk())
144				return as_chunk()[index];
145			else
146				return as_bits()[index];
147		}
148	
149		bool operator==(const VariableBits &other) const
150		{
151			if (bitwidth() != other.bitwidth())
152				return false;
153			if (is_chunk() && other.is_chunk())
154				return as_chunk() == other.as_chunk();
155			for (uint64_t i = 0; i < bitwidth(); i++)
156				if (!((*this)[i] == other[i]))
157					return false;
158			return true;
159		}
160	
161		bool operator!=(const VariableBits &other) const { return !(*this == other); }
162	
163		void append(const VariableBit bit)
164		{
165			if (is_chunk()) {
166				auto &chunk = as_chunk();
167				if (chunk.length == 0) {
168					chunk = {bit.variable, bit.offset, 1};
169					return;
170				}
171				if (bit.variable == chunk.variable && bit.offset == chunk.base + chunk.length) {
172					chunk.length++;
173					return;
174				}
175				unpack();
176			}
177			as_bits().push_back(bit);
178		}
179	
180		void append(const VariableBits &other)
181		{
182			if (other.empty())
183				return;
184			if (is_chunk() && other.is_chunk()) {
185				auto &chunk = as_chunk();
186				auto &other_chunk = other.as_chunk();
187				if (chunk.length == 0) {
188					chunk = other_chunk;
189					return;
190				}
191				if (chunk.variable == other_chunk.variable &&
192						other_chunk.base == chunk.base + chunk.length) {
193					chunk.length += other_chunk.length;
194					return;
195				}
196			}
197			unpack();
198			if (other.is_chunk()) {
199				auto &other_chunk = other.as_chunk();
200				for (uint64_t i = 0; i < other_chunk.length; i++)
201					as_bits().push_back(other_chunk[i]);
202			} else {
203				auto &bits = as_bits();
204				auto &other_bits = other.as_bits();
205				bits.insert(bits.end(), other_bits.begin(), other_bits.end());
206			}
207		}
208	
209		void remove(int index)
210		{
211			unpack();
212			auto &bits = as_bits();
213			log_assert(index >= 0 && index < (int)bits.size());
214			bits.erase(bits.begin() + index);
215		}
216	
217		void reserve(uint64_t n)
218		{
219			unpack();
220			as_bits().reserve(n);
221		}
222	
223		VariableBits extract(uint64_t base, uint64_t width) const
224		{
225			if (is_chunk()) {
226				auto &chunk = as_chunk();
227				return VariableBits(VariableChunk{chunk.variable, chunk.base + base, width});
228			}
229			VariableBits ret;
230			for (uint64_t i = base, j = 0; j < width; i++, j++)
231				ret.append(as_bits()[i]);
232			return ret;
233		}
234	
235		void sort()
236		{
237			unpack();
238			auto &bits = as_bits();
239			std::sort(bits.begin(), bits.end());
240		}
241	
242		void sort_and_unify()
243		{
244			sort();
245			auto &bits = as_bits();
246			auto unified_end = std::unique(bits.begin(), bits.end());
247			bits.erase(unified_end, bits.end());
248		}
249	
250		bool has_dummy_bits() const
251		{
252			if (is_chunk())
253				return as_chunk().variable.kind == Variable::Dummy;
254			for (auto chunk : chunks()) {
255				if (chunk.variable.kind == Variable::Dummy)
256					return true;
257			}
258			return false;
259		}
260	
261		bool has_special_nets();
262	
263		class const_bit_iterator
264		{
265			const VariableBits *container;
266			int index;
267	
268		public:
269			using iterator_category = std::random_access_iterator_tag;
270			using value_type = VariableBit;
271			using difference_type = int;
272	
273			const_bit_iterator(const VariableBits *container, int index)
274				: container(container), index(index)
275			{}
276			VariableBit operator*() const { return (*container)[index]; }
277			const_bit_iterator &operator++()
278			{
279				index++;
280				return *this;
281			}
282			const_bit_iterator operator++(int)
283			{
284				auto tmp = *this;
285				index++;
286				return tmp;
287			}
288			const_bit_iterator &operator--()
289			{
290				index--;
291				return *this;
292			}
293			const_bit_iterator operator+(int n) const { return {container, index + n}; }
294			const_bit_iterator operator-(int n) const { return {container, index - n}; }
295			int operator-(const const_bit_iterator &other) const { return index - other.index; }
296			auto operator<=>(const const_bit_iterator &other) const { return index <=> other.index; }
297			bool operator==(const const_bit_iterator &other) const = default;
298		};
299	
300		const_bit_iterator begin() const { return const_bit_iterator(this, 0); }
301		const_bit_iterator end() const { return const_bit_iterator(this, bitwidth()); }
302	
303		class iterator_base
304		{
305		protected:
306			const VariableBits &container;
307			uint64_t offset;
308			VariableChunk chunk;
309	
310			void incr()
311			{
312				offset += chunk.length;
313				if (offset < container.bitwidth()) {
314					log_assert(!container.is_chunk());
315					auto &bits = container.as_bits();
316					chunk = {bits[offset].variable, bits[offset].offset, 1};
317					fixup_chunk();
318				}
319			}
320	
321		public:
322			using iterator_category = std::input_iterator_tag;
323	
324			iterator_base(const VariableBits &container, uint64_t offset)
325				: container(container), offset(offset)
326			{
327				if (offset < container.bitwidth()) {
328					if (container.is_chunk()) {
329						chunk = container.as_chunk();
330					} else {
331						auto &bits = container.as_bits();
332						chunk = {bits[offset].variable, bits[offset].offset, 1};
333						fixup_chunk();
334					}
335				}
336			}
337	
338			void fixup_chunk()
339			{
340				auto &bits = container.as_bits();
341				while (offset + chunk.length < bits.size() &&
342						bits[offset + chunk.length].variable == chunk.variable &&
343						bits[offset + chunk.length].offset == chunk.base + chunk.length) {
344					chunk.length++;
345				}
346			}
347	
348			bool operator==(const iterator_base &other) const { return offset == other.offset; }
349			bool operator!=(const iterator_base &other) const { return !(*this == other); }
350		};
351	
352		class chunk_iterator : public iterator_base
353		{
354		public:
355			using value_type = VariableChunk;
356			chunk_iterator(const VariableBits &bits, uint64_t offset) : iterator_base(bits, offset) {}
357			VariableChunk operator*() const { return chunk; }
358			chunk_iterator &operator++()
359			{
360				incr();
361				return *this;
362			}
363		};
364	
365		class chunk_list
366		{
367		public:
368			chunk_iterator begin() const { return chunk_iterator(bits, 0); };
369			chunk_iterator end() const { return chunk_iterator(bits, bits.bitwidth()); };
370	
371		protected:
372			chunk_list(const VariableBits &bits) : bits(bits) {};
373			friend class VariableBits;
374	
375		private:
376			const VariableBits &bits;
377		};
378	
379		chunk_list chunks() const { return chunk_list(*this); }
380	
381		class chunk_span_iterator : public iterator_base
382		{
383		public:
384			using value_type = std::tuple<size_t, size_t, VariableChunk>;
385			chunk_span_iterator(const VariableBits &bits, uint64_t offset) : iterator_base(bits, offset)
386			{}
387			std::tuple<size_t, size_t, VariableChunk> operator*() const
388			{
389				return std::make_tuple(offset, chunk.length, chunk);
390			}
391			chunk_span_iterator &operator++()
392			{
393				incr();
394				return *this;
395			}
396		};
397	
398		class chunk_span_list
399		{
400		public:
401			chunk_span_iterator begin() const { return chunk_span_iterator(bits, 0); };
402			chunk_span_iterator end() const { return chunk_span_iterator(bits, bits.bitwidth()); };
403	
404		protected:
405			chunk_span_list(const VariableBits &bits) : bits(bits) {};
406			friend class VariableBits;
407	
408		private:
409			const VariableBits &bits;
410		};
411	
412		chunk_span_list chunk_spans() const { return chunk_span_list(*this); }
413	};
414	
415	}; // namespace slang_frontend
