RTLIL::SigSpec VariableState::evaluate(NetlistContext &netlist, VariableBits vbits)
{
	RTLIL::SigSpec ret;
	for (auto vbit : vbits) {
		if (vbit.variable.kind == Variable::Dummy) {
			ret.append(RTLIL::Sx);
